\begin{array}{l}
\text { Spherical coordinate system }\\
\begin{aligned}
r & =\sqrt{x^{2}+y^{2}+z^{2}} \\
\theta & =\arccos \left(\frac{z}{x^{2}+y^{2}+z^{2}}\right) \\
\phi & =\arctan \left(\frac{y}{x}\right)
\end{aligned}\\
\left.\begin{array}{l}
\vec{e}_{r}=\sin \theta \cos \phi \vec{i}+\sin \theta \sin \phi \vec{j}+\cos \theta \vec{k} \\
\vec{e}_{\theta}=\cos \theta \cos \phi \vec{i}+\cos \theta \sin \phi \vec{j}-\sin \theta \vec{k} \\
\vec{e}_{\phi}=-\sin \phi \vec{i}+\cos \phi \vec{j}
\end{array}\right\} \text { Vectors }\\
\text { 2-5 }
\end{array}

